def caesar_encrypt(plaintext: str, shift: int) -> str:
    result = ""
    for char in plaintext.upper():
        if char.isalpha():
            shifted = (ord(char) - ord('A') + shift) % 26
            result += chr(shifted + ord('A'))
        else:
            result += char
    return result

def caesar_decrypt(ciphertext: str, shift: int) -> str:
    return caesar_encrypt(ciphertext, -shift)

def break_caesar(ciphertext: str) -> list:
    results = []
    for shift in range(1, 26):
        decrypted = caesar_decrypt(ciphertext, shift)
        results.append((shift, decrypted))
    return results

def caesar_decrypt(ciphertext: str, shift: int) -> str:
    result = ""
    for char in ciphertext.upper():
        if char.isalpha():
            shifted = (ord(char) - ord('A') - shift) % 26
            result += chr(shifted + ord('A'))
        else:
            result += char
    return result

def identify_security_property(scenario: str) -> str:
    mapping = {
        'encrypt': 'confidentiality',
        'hash': 'integrity',
        'password': 'authentication',
        'signature': 'non-repudiation'
    }
    return mapping.get(scenario.lower(), 'unknown')

def key_space_size(key_bits: int) -> int:
    return 2 ** key_bits

def brute_force_time(key_bits: int, ops_per_second: int) -> float:
    total_keys = key_space_size(key_bits)
    seconds = total_keys / ops_per_second
    years = seconds / (60 * 60 * 24 * 365)
    return years

def compare_security(bits1: int, bits2: int) -> str:
    ratio = 2 ** (bits2 - bits1)
    return f"{bits2}-bit is {ratio:,}x harder to break than {bits1}-bit"

def classify_crypto_system(uses_same_key: bool, 
                           key_exchange_needed: bool,
                           has_public_key: bool) -> str:
    if uses_same_key and not has_public_key:
        return 'symmetric'
    elif not uses_same_key and has_public_key:
        return 'asymmetric'
    else:
        # Edge cases - determine by public key presence
        return 'asymmetric' if has_public_key else 'symmetric'
